mapper.select:
/* TM_ECS_INTN_USR_SYS_ATHR_retrieveUsrSysAthr */ SELECT A.SYS_DIV_CD AS INTN_SYS_DIV_CD, (SELECT CMMN_CD_NM FROM SCM.TC_SC_CD WHERE cls_cd = 'SCM_0000' AND A.SYS_DIV_CD = CMMN_CD) AS INTN_SYS_DIV_NM, ADMIN_DIV_CD, A.USR_ID, (SELECT KORNAME FROM HRM.VM_HR01601 WHERE EMPNO = A.USR_ID) AS USR_NM, DTY_NM, CONECT_IP, ATHR_ORDR, A.USE_YN FROM TM_ECS_INTN_USR_SYS_ATHR A WHERE 1 = 1
AND A.USE_YN = #{useYn}
/* 사용자 id 정보가 있을 경우 */ AND A.USR_ID = #{usrId}
/* 시스템구분코드가 있을 경우 */ AND A.SYS_DIV_CD = #{intnSysDivCd}
/* 관리자구분코드가 있을 경우 */ AND A.ADMIN_DIV_CD = #{adminDivCd}
ORDER BY A.SYS_DIV_CD, A.ATHR_ORDR, A.ADMIN_DIV_CD, A.USR_ID

mapper.update:
/* TM_ECS_INTN_USR_SYS_ATHR_updateUsrSysAthr */
UPDATE
	TM_ECS_INTN_USR_SYS_ATHR
SET
	DTY_NM = #{dtyNm},
	CONECT_IP = #{conectIp},
	ATHR_ORDR = #{athrOrdr},
	USE_YN = NVL(#{useYn}, 'N'),
	LAST_UPDT_DT = SYSDATE,
	LAST_UPDUSR_ID = #{lastUpdusrId}
WHERE
	USR_ID = #{usrId}
	AND SYS_DIV_CD = #{intnSysDivCd}
	AND ADMIN_DIV_CD = #{adminDivCd}

mapper.delete:
/* TM_ECS_INTN_USR_SYS_ATHR_deleteUsrSysAthr */
DELETE FROM
	TM_ECS_INTN_USR_SYS_ATHR
WHERE
	USR_ID = #{usrId}
	AND SYS_DIV_CD = #{intnSysDivCd}
	AND ADMIN_DIV_CD = #{adminDivCd}
